//! Regression test for cache-stable prompt prefixes across same-plan tasks.

use roko_compose::templates::{PlanSlice, TaskImplInput, TaskImplTemplate};
use roko_compose::{ContextStrategy, PromptAssembler};

fn repeated_block(heading: &str, line: &str, count: usize) -> String {
    let mut out = String::from(heading);
    out.push('\n');
    for _ in 0..count {
        out.push_str(line);
        out.push('\n');
    }
    out
}

fn build_prompt(
    task_id: &str,
    task_title: &str,
    task_files: &[&str],
    acceptance_criteria: &[&str],
) -> String {
    let template = TaskImplTemplate;
    let input = TaskImplInput {
        agents_md: repeated_block(
            "# AGENTS.md",
            "- Prefer wiring existing modules over reimplementation.",
            10,
        ),
        plan: PlanSlice {
            num: "013".into(),
            base: "model-routing".into(),
            title: "Architectural gaps".into(),
            content: repeated_block(
                "## Plan Context",
                "- Keep role and workspace layers byte-stable across tasks in the same plan.",
                24,
            ),
        },
        task_id: task_id.into(),
        task_title: task_title.into(),
        task_files: task_files.iter().map(|path| (*path).to_string()).collect(),
        acceptance_criteria: acceptance_criteria
            .iter()
            .map(|criterion| (*criterion).to_string())
            .collect(),
        brief: repeated_block(
            "## Brief",
            "- Preserve prompt-cache reuse by keeping shared sections identical.",
            16,
        ),
        workspace_map: repeated_block("## Workspace Map", "- crates/roko-compose/src/*", 22),
        prd2_extract: repeated_block(
            "## PRD2 Extract",
            "- Providers with automatic prefix caching depend on byte-identical shared prefixes.",
            14,
        ),
        cross_plan_context: repeated_block(
            "## Cross-Plan Context",
            "- Task sequencing should not perturb stable prompt layers.",
            12,
        ),
        ..TaskImplInput::default()
    };

    PromptAssembler::new()
        .assemble_from(&template, &input, None, ContextStrategy::Full)
        .prompt
}

#[test]
fn cache_prefix_stable_across_tasks() {
    let prompt_1 = build_prompt(
        "2K.13",
        "Insert Anthropic cache markers",
        &["crates/roko-agent/src/translate/claude.rs"],
        &["Anthropic requests include cache_control boundaries."],
    );
    let prompt_2 = build_prompt(
        "2K.14",
        "Normalize prompt content",
        &["crates/roko-compose/src/system_prompt_builder.rs"],
        &["Equivalent prompts normalize to identical bytes."],
    );
    let prompt_3 = build_prompt(
        "2K.15",
        "Verify cache prefix stability",
        &["crates/roko-compose/tests/cache_stability.rs"],
        &["Shared prompt prefix remains identical across plan tasks."],
    );

    let role_len_1 = prompt_1.find("## Plan Context").unwrap();
    let role_len_2 = prompt_2.find("## Plan Context").unwrap();
    let role_len_3 = prompt_3.find("## Plan Context").unwrap();
    assert_eq!(role_len_1, role_len_2);
    assert_eq!(role_len_1, role_len_3);
    assert_eq!(&prompt_1[..role_len_1], &prompt_2[..role_len_1]);
    assert_eq!(&prompt_1[..role_len_1], &prompt_3[..role_len_1]);

    let ws_len_1 = prompt_1.find("## Your Assignment").unwrap();
    let ws_len_2 = prompt_2.find("## Your Assignment").unwrap();
    let ws_len_3 = prompt_3.find("## Your Assignment").unwrap();
    assert_eq!(ws_len_1, ws_len_2);
    assert_eq!(ws_len_1, ws_len_3);
    assert_eq!(&prompt_1[..ws_len_1], &prompt_2[..ws_len_1]);
    assert_eq!(&prompt_1[..ws_len_1], &prompt_3[..ws_len_1]);

    assert!(ws_len_1 * 100 / prompt_1.len() >= 60);
    assert!(ws_len_2 * 100 / prompt_2.len() >= 60);
    assert!(ws_len_3 * 100 / prompt_3.len() >= 60);
}

//! End-to-end CLI test.
//!
//! Spawns the `roko` binary against a tempdir: runs `init`, then `run`
//! with `cat` as the agent backend, and asserts that `.roko/signals.jsonl`
//! contains the full signal set (`Prompt`, `AgentOutput`, `Episode`, etc.).

use assert_cmd::Command;
use std::fs;
use tempfile::TempDir;

#[test]
fn init_run_produces_expected_signals() {
    let tmp = TempDir::new().unwrap();
    let workdir = tmp.path();

    // `roko init <workdir>`
    Command::cargo_bin("roko")
        .unwrap()
        .arg("init")
        .arg(workdir)
        .assert()
        .success();

    // Verify the init artifacts exist.
    assert!(workdir.join(".roko").is_dir(), ".roko directory missing");
    assert!(
        workdir.join(".roko/signals.jsonl").exists(),
        "signals.jsonl missing"
    );
    assert!(workdir.join("roko.toml").exists(), "roko.toml missing");

    // `roko run "hello"` with cat as the agent (the default in roko.toml) and
    // the default `true` shell gate → both agent and gate pass.
    Command::cargo_bin("roko")
        .unwrap()
        .arg("run")
        .arg("write a hello function")
        .arg("--workdir")
        .arg(workdir)
        .assert()
        .success();

    // Read the JSONL log and check that every required kind is present.
    let log = fs::read_to_string(workdir.join(".roko/signals.jsonl")).unwrap();
    assert!(!log.is_empty(), "signals.jsonl is empty after run");

    let mut saw_prompt_section = false;
    let mut saw_prompt = false;
    let mut saw_agent_output = false;
    let mut saw_episode = false;
    let mut saw_verdict = false;
    for line in log.lines() {
        if line.trim().is_empty() {
            continue;
        }
        // The JSONL kind field is a snake_case enum tag.
        if line.contains("\"prompt_section\"") {
            saw_prompt_section = true;
        }
        if line.contains("\"prompt\"") {
            saw_prompt = true;
        }
        if line.contains("\"agent_output\"") {
            saw_agent_output = true;
        }
        if line.contains("\"episode\"") {
            saw_episode = true;
        }
        if line.contains("\"gate_verdict\"") {
            saw_verdict = true;
        }
    }
    assert!(saw_prompt_section, "no PromptSection signal persisted");
    assert!(saw_prompt, "no Prompt signal persisted");
    assert!(saw_agent_output, "no AgentOutput signal persisted");
    assert!(saw_episode, "no Episode signal persisted");
    assert!(saw_verdict, "no GateVerdict signal persisted");

    // `roko status` should succeed and mention non-zero signals.
    let status = Command::cargo_bin("roko")
        .unwrap()
        .arg("status")
        .arg("--workdir")
        .arg(workdir)
        .assert()
        .success();
    let stdout = String::from_utf8_lossy(&status.get_output().stdout).into_owned();
    assert!(
        stdout.contains("signal counts"),
        "status output missing header: {stdout}"
    );
    assert!(
        stdout.contains("episode"),
        "status output missing episode kind: {stdout}"
    );
    assert!(
        stdout.contains("most recent episode"),
        "status did not report an episode: {stdout}"
    );
}

#[test]
fn status_cfactor_reports_trend_and_components() {
    let tmp = TempDir::new().unwrap();
    let workdir = tmp.path();

    Command::cargo_bin("roko")
        .unwrap()
        .arg("init")
        .arg(workdir)
        .assert()
        .success();

    let learn_dir = workdir.join(".roko").join("learn");
    fs::create_dir_all(&learn_dir).unwrap();

    // Episode must live under learn/ — that is where LearningPaths::under()
    // resolves episodes_jsonl when refresh_cfactor_snapshot is called with
    // the learn directory as root.
    let now = chrono::Utc::now();
    let episode_ts = now.to_rfc3339();
    let episode = serde_json::json!({
        "kind": "agent_turn",
        "id": "ep-1",
        "timestamp": episode_ts,
        "agent_id": "agent-a",
        "task_id": "task-a",
        "input_signal_hash": "",
        "output_signal_hash": "",
        "episode_id": "episode-1",
        "agent_template": "Implementer",
        "model": "claude-sonnet",
        "trigger_kind": "manual",
        "trigger_signal_hash": "",
        "started_at": episode_ts,
        "completed_at": episode_ts,
        "duration_secs": 1.0,
        "gate_verdicts": [],
        "usage": {
            "input_tokens": 100,
            "output_tokens": 50,
            "cache_read_tokens": 0,
            "cache_write_tokens": 0,
            "cost_usd": 1.0,
            "cost_usd_without_cache": 1.0,
            "wall_ms": 100
        },
        "success": true,
        "turns": 1,
        "tokens_used": 150,
        "external_actions": [],
        "failure_reason": null,
        "headline": false,
        "extra": {}
    });
    fs::write(learn_dir.join("episodes.jsonl"), episode.to_string() + "\n").unwrap();

    // Use timestamps relative to now so the history entries are always
    // inside the 7-day trend window used by trend_arrow.
    let earlier_ts = (now - chrono::Duration::days(5)).to_rfc3339();
    let recent_ts = (now - chrono::Duration::days(2)).to_rfc3339();
    let earlier = serde_json::json!({
        "overall": 0.25,
        "components": {
            "gate_pass_rate": 0.20,
            "cost_efficiency": 0.20,
            "speed": 0.20,
            "first_try_rate": 0.20,
            "knowledge_growth": 0.20,
            "turn_taking_equality": 0.20
        },
        "computed_at": earlier_ts,
        "episode_count": 1
    });
    let recent = serde_json::json!({
        "overall": 0.40,
        "components": {
            "gate_pass_rate": 0.30,
            "cost_efficiency": 0.30,
            "speed": 0.30,
            "first_try_rate": 0.30,
            "knowledge_growth": 0.10,
            "turn_taking_equality": 0.30
        },
        "computed_at": recent_ts,
        "episode_count": 1
    });

    fs::write(
        learn_dir.join("c-factor.jsonl"),
        [earlier.to_string(), recent.to_string()].join("\n") + "\n",
    )
    .unwrap();

    let status = Command::cargo_bin("roko")
        .unwrap()
        .arg("status")
        .arg("--cfactor")
        .arg("--workdir")
        .arg(workdir)
        .assert()
        .success();

    let stdout = String::from_utf8_lossy(&status.get_output().stdout).into_owned();
    assert!(
        stdout.contains("c-factor:"),
        "status output missing c-factor summary: {stdout}"
    );
    assert!(
        stdout.contains("trend="),
        "status output missing trend: {stdout}"
    );
    assert!(
        stdout.contains("gate="),
        "status output missing components: {stdout}"
    );
    assert!(
        stdout.contains('↑'),
        "status output missing upward trend arrow: {stdout}"
    );
}

#[test]
fn run_fails_when_gate_fails() {
    let tmp = TempDir::new().unwrap();
    let workdir = tmp.path();

    Command::cargo_bin("roko")
        .unwrap()
        .arg("init")
        .arg(workdir)
        .assert()
        .success();

    // Replace roko.toml with one whose gate is `false` (always fails).
    let failing_config = r#"
[agent]
command = "cat"
args = []
timeout_ms = 30000

[prompt]
token_budget = 1000
role = "You are a Roko agent."

[[gate]]
kind = "shell"
program = "false"
args = []
timeout_ms = 5000
"#;
    fs::write(workdir.join("roko.toml"), failing_config).unwrap();

    // Exit code should be non-zero because the gate failed.
    Command::cargo_bin("roko")
        .unwrap()
        .arg("run")
        .arg("smoke")
        .arg("--workdir")
        .arg(workdir)
        .assert()
        .failure();

    // But the signals should still be persisted — the failure is reported, not swallowed.
    let log = fs::read_to_string(workdir.join(".roko/signals.jsonl")).unwrap();
    assert!(log.contains("\"gate_verdict\""));
    assert!(log.contains("\"episode\""));
}

#[test]
fn prompt_files_are_injected_as_sections() {
    let tmp = TempDir::new().unwrap();
    let workdir = tmp.path();

    Command::cargo_bin("roko")
        .unwrap()
        .arg("init")
        .arg(workdir)
        .assert()
        .success();

    // Write a fixture file and a config that injects it.
    fs::write(
        workdir.join("issue.md"),
        "# Bug report\nThe `greet()` function returns the wrong string.\n",
    )
    .unwrap();
    let config = r#"
[agent]
command = "cat"
args = []
timeout_ms = 30000

[prompt]
token_budget = 10000
role = "You are a Rust engineer."

[[prompt.files]]
path = "issue.md"
name = "issue"
priority = "high"

[[gate]]
kind = "shell"
program = "true"
args = []
timeout_ms = 5000
"#;
    fs::write(workdir.join("roko.toml"), config).unwrap();

    let out = Command::cargo_bin("roko")
        .unwrap()
        .arg("run")
        .arg("Suggest a fix for the bug described in the issue file.")
        .arg("--workdir")
        .arg(workdir)
        .assert()
        .success();

    // The cat-echoed output should contain the injected file contents.
    let stdout = String::from_utf8_lossy(&out.get_output().stdout).into_owned();
    assert!(
        stdout.contains("cat"),
        "expected agent output header: {stdout}"
    );

    let log = fs::read_to_string(workdir.join(".roko/signals.jsonl")).unwrap();
    assert!(
        log.contains("Bug report"),
        "file contents should have reached the prompt: {log}"
    );
    // There should be 3 prompt sections now (role + issue-file + task).
    let section_count = log.matches("\"prompt_section\"").count();
    assert!(
        section_count >= 3,
        "expected >=3 prompt sections, got {section_count}"
    );
}

#[test]
fn clean_output_strips_thinking_trace() {
    let tmp = TempDir::new().unwrap();
    let workdir = tmp.path();

    Command::cargo_bin("roko")
        .unwrap()
        .arg("init")
        .arg(workdir)
        .assert()
        .success();

    // Use `printf` as the agent backend — it emits a fake thinking trace
    // followed by a short answer. This bypasses needing a real LLM.
    let config = r#"
[agent]
command = "sh"
args = ["-c", "printf 'Thinking...\\nstep 1\\nstep 2\\n...done thinking.\\n\\nFinal answer: 42\\n'"]
timeout_ms = 10000
clean_output = true

[prompt]
token_budget = 1000
role = "You are a test agent."

[[gate]]
kind = "shell"
program = "true"
args = []
timeout_ms = 5000
"#;
    fs::write(workdir.join("roko.toml"), config).unwrap();

    Command::cargo_bin("roko")
        .unwrap()
        .arg("run")
        .arg("whatever")
        .arg("--workdir")
        .arg(workdir)
        .assert()
        .success();

    // The cleaned AgentOutput should contain only "Final answer: 42".
    let log = fs::read_to_string(workdir.join(".roko/signals.jsonl")).unwrap();
    // Raw AgentMessage trace has the full thinking block
    assert!(
        log.contains("...done thinking."),
        "raw trace not persisted: {log}"
    );
    // At least one AgentOutput signal must have cleaned=true and NOT contain 'step 1'.
    let has_cleaned = log
        .lines()
        .filter(|l| l.contains("\"cleaned\":\"true\""))
        .any(|l| l.contains("Final answer") && !l.contains("step 1"));
    assert!(
        has_cleaned,
        "cleaned AgentOutput missing or not sanitized: {log}"
    );
}

//! Full lifecycle integration test (I.2.8).
//!
//! Verifies that a plan transitions through the complete happy-path
//! lifecycle via the `ParallelExecutor`, and that the audit chain
//! records an entry for each transition.

#![allow(clippy::unwrap_used)]

use roko_core::{PhaseKind, PlanPhase};
use roko_orchestrator::safety::audit_chain::AuditChain;
use roko_orchestrator::{
    ExecutorAction, ExecutorConfig, ExecutorEvent, ParallelExecutor, PlanState,
};

/// Full lifecycle: Queued -> Enriching -> Implementing -> Gating ->
/// Verifying -> Reviewing -> DocRevision -> Merging -> Complete.
///
/// Uses `apply_event()` at each step, checks the final state is
/// `Complete`, and verifies the audit chain has one entry per
/// transition.
#[test]
fn full_lifecycle_with_audit_chain() {
    let chain = AuditChain::new();
    let mut ex = ParallelExecutor::new(ExecutorConfig::default()).with_audit_chain(chain.clone());

    ex.add_plan(PlanState::new("lifecycle-1"));

    // Tick should suggest DispatchPlan for the queued plan.
    let actions = ex.tick();
    assert_eq!(actions.len(), 1);
    assert!(matches!(
        &actions[0],
        ExecutorAction::DispatchPlan { plan_id } if plan_id == "lifecycle-1"
    ));

    // 1. Queued -> Enriching
    let phase = ex
        .apply_event("lifecycle-1", &ExecutorEvent::Start)
        .unwrap();
    assert_eq!(phase.kind(), PhaseKind::Enriching);

    // 2. Enriching -> Implementing
    let phase = ex
        .apply_event("lifecycle-1", &ExecutorEvent::EnrichmentDone)
        .unwrap();
    assert_eq!(phase.kind(), PhaseKind::Implementing);

    // 3. Implementing -> Gating
    let phase = ex
        .apply_event("lifecycle-1", &ExecutorEvent::ImplementationDone)
        .unwrap();
    assert_eq!(phase.kind(), PhaseKind::Gating);

    // 4. Gating -> Verifying
    let phase = ex
        .apply_event("lifecycle-1", &ExecutorEvent::GatePassed)
        .unwrap();
    assert_eq!(phase.kind(), PhaseKind::Verifying);

    // 5. Verifying -> Reviewing
    let phase = ex
        .apply_event("lifecycle-1", &ExecutorEvent::VerifyPassed)
        .unwrap();
    assert_eq!(phase.kind(), PhaseKind::Reviewing);

    // 6. Reviewing -> DocRevision
    let phase = ex
        .apply_event("lifecycle-1", &ExecutorEvent::ReviewApproved)
        .unwrap();
    assert_eq!(phase.kind(), PhaseKind::DocRevision);

    // 7. DocRevision -> Merging
    let phase = ex
        .apply_event("lifecycle-1", &ExecutorEvent::DocRevisionDone)
        .unwrap();
    assert_eq!(phase.kind(), PhaseKind::Merging);

    // 8. Merging -> Complete
    let phase = ex
        .apply_event("lifecycle-1", &ExecutorEvent::MergeSucceeded)
        .unwrap();
    assert_eq!(phase, PlanPhase::Complete);

    // Final state is Complete.
    let state = ex.plan_state("lifecycle-1").unwrap();
    assert!(state.is_terminal());
    assert_eq!(state.current_phase, PlanPhase::Complete);

    // Audit chain has exactly 8 entries (one per transition).
    let audit = ex.audit_chain().unwrap();
    assert_eq!(
        audit.len(),
        8,
        "expected 8 audit entries, got {}",
        audit.len()
    );
    assert!(audit.verify(), "audit chain must be valid");

    // All entries should reference the plan_id as the resource.
    let entries = audit.iter();
    for entry in &entries {
        assert_eq!(entry.resource, "lifecycle-1");
        assert_eq!(entry.actor, "executor");
        assert!(entry.kind.starts_with("phase."));
    }

    // Completed plans list contains our plan.
    assert!(ex.completed_plans().contains(&"lifecycle-1".to_string()));
}

/// Verify executor works correctly without an audit chain (default behaviour).
#[test]
fn lifecycle_without_audit_chain() {
    let mut ex = ParallelExecutor::new(ExecutorConfig::default());
    ex.add_plan(PlanState::new("no-audit"));

    ex.apply_event("no-audit", &ExecutorEvent::Start).unwrap();
    ex.apply_event("no-audit", &ExecutorEvent::EnrichmentDone)
        .unwrap();
    ex.apply_event("no-audit", &ExecutorEvent::ImplementationDone)
        .unwrap();
    ex.apply_event("no-audit", &ExecutorEvent::GatePassed)
        .unwrap();
    ex.apply_event("no-audit", &ExecutorEvent::VerifyPassed)
        .unwrap();
    ex.apply_event("no-audit", &ExecutorEvent::ReviewApproved)
        .unwrap();
    ex.apply_event("no-audit", &ExecutorEvent::DocRevisionDone)
        .unwrap();
    ex.apply_event("no-audit", &ExecutorEvent::MergeSucceeded)
        .unwrap();

    assert!(ex.plan_state("no-audit").unwrap().is_terminal());
    assert!(ex.audit_chain().is_none());
}

/// Multiple plans go through the lifecycle in parallel, audit chain
/// tracks all of them.
#[test]
fn multi_plan_lifecycle_with_audit_chain() {
    let chain = AuditChain::new();
    let mut ex = ParallelExecutor::new(ExecutorConfig::default()).with_audit_chain(chain.clone());

    ex.add_plan(PlanState::new("plan-a"));
    ex.add_plan(PlanState::new("plan-b"));

    // Advance plan-a fully.
    for event in &[
        ExecutorEvent::Start,
        ExecutorEvent::EnrichmentDone,
        ExecutorEvent::ImplementationDone,
        ExecutorEvent::GatePassed,
        ExecutorEvent::VerifyPassed,
        ExecutorEvent::ReviewApproved,
        ExecutorEvent::DocRevisionDone,
        ExecutorEvent::MergeSucceeded,
    ] {
        ex.apply_event("plan-a", event).unwrap();
    }

    // Advance plan-b partially (to Gating).
    for event in &[
        ExecutorEvent::Start,
        ExecutorEvent::EnrichmentDone,
        ExecutorEvent::ImplementationDone,
    ] {
        ex.apply_event("plan-b", event).unwrap();
    }

    assert_eq!(
        ex.plan_state("plan-a").unwrap().current_phase,
        PlanPhase::Complete
    );
    assert_eq!(
        ex.plan_state("plan-b").unwrap().current_phase.kind(),
        PhaseKind::Gating
    );

    // 8 from plan-a + 3 from plan-b = 11.
    assert_eq!(chain.len(), 11);
    assert!(chain.verify());
}

//! Integration test: `CompileGate` against a real cargo project.
//!
//! Creates a tiny cargo crate in a tempdir, runs `CompileGate` against it,
//! verifies the verdict. Then corrupts the source and runs again to verify
//! the failure path works too.

use async_trait::async_trait;
use roko_core::{Body, Context, Gate, Kind, Signal, Substrate};
use roko_gate::{BuildSystem, CompileGate, GatePayload};
use roko_std::MemorySubstrate;
use std::path::Path;
use tempfile::TempDir;
use tokio::fs;

async fn scaffold_cargo_project(root: &Path, lib_rs: &str) {
    fs::write(
        root.join("Cargo.toml"),
        r#"[package]
name = "roko_gate_fixture"
version = "0.1.0"
edition = "2021"

[lib]
path = "src/lib.rs"
"#,
    )
    .await
    .unwrap();
    fs::create_dir_all(root.join("src")).await.unwrap();
    fs::write(root.join("src/lib.rs"), lib_rs).await.unwrap();
}

fn payload_signal(working_dir: &Path) -> Signal {
    let payload = GatePayload::in_dir(working_dir).with_label("test-fixture");
    Signal::builder(Kind::Task)
        .body(Body::from_json(&payload).unwrap())
        .build()
}

#[tokio::test]
async fn compile_gate_passes_on_valid_project() {
    let tmp = TempDir::new().unwrap();
    scaffold_cargo_project(tmp.path(), "pub fn greet() -> &'static str { \"hello\" }\n").await;

    let gate = CompileGate::new(BuildSystem::Cargo).with_timeout_ms(120_000);
    let signal = payload_signal(tmp.path());

    let verdict = gate.verify(&signal, &Context::now()).await;

    assert!(
        verdict.passed,
        "valid project should pass; reason={} detail={:?}",
        verdict.reason, verdict.detail
    );
    assert_eq!(verdict.gate, "compile:cargo");
    assert!(verdict.duration_ms > 0);
}

#[tokio::test]
async fn compile_gate_fails_on_syntax_error() {
    let tmp = TempDir::new().unwrap();
    scaffold_cargo_project(tmp.path(), "pub fn broken() -> { missing body }\n").await;

    let gate = CompileGate::new(BuildSystem::Cargo).with_timeout_ms(120_000);
    let signal = payload_signal(tmp.path());

    let verdict = gate.verify(&signal, &Context::now()).await;

    assert!(!verdict.passed, "syntax error should fail the gate");
    assert!(
        verdict.reason.contains("error"),
        "reason should mention error: {}",
        verdict.reason
    );
    // Detail should contain stderr with the actual rustc error.
    let detail = verdict.detail.as_deref().unwrap_or("");
    assert!(
        detail.contains("error"),
        "detail should contain compiler error: {detail}"
    );
}

#[tokio::test]
async fn compile_gate_fails_on_missing_dir() {
    let gate = CompileGate::new(BuildSystem::Cargo).with_timeout_ms(10_000);
    let payload = GatePayload::in_dir("/nonexistent/path/xyz");
    let signal = Signal::builder(Kind::Task)
        .body(Body::from_json(&payload).unwrap())
        .build();

    let verdict = gate.verify(&signal, &Context::now()).await;
    assert!(!verdict.passed);
}

#[tokio::test]
async fn compile_gate_rejects_malformed_payload() {
    let gate = CompileGate::new(BuildSystem::Cargo);
    // A signal with no body, or a non-GatePayload body, should be rejected.
    let signal = Signal::builder(Kind::Task)
        .body(Body::text("not a payload"))
        .build();

    let verdict = gate.verify(&signal, &Context::now()).await;
    assert!(!verdict.passed);
    assert!(verdict.reason.contains("not a GatePayload"));
}

/// End-to-end: gate → verdict → persist as Signal → re-query.
///
/// This demonstrates the architectural flow: a gate's verdict becomes a
/// signal that lives in a substrate, ready to be consumed by policies.
#[tokio::test]
async fn verdict_flows_back_into_substrate_as_signal() {
    let tmp = TempDir::new().unwrap();
    scaffold_cargo_project(tmp.path(), "pub fn x() -> i32 { 1 }\n").await;

    let substrate = MemorySubstrate::named("verdicts");
    let gate = CompileGate::new(BuildSystem::Cargo).with_timeout_ms(120_000);

    // 1. Task signal.
    let task_signal = payload_signal(tmp.path());
    substrate.put(task_signal.clone()).await.unwrap();

    // 2. Gate verifies.
    let verdict = gate.verify(&task_signal, &Context::now()).await;
    assert!(verdict.passed);

    // 3. Wrap the verdict as a GateVerdict signal derived from the task.
    let verdict_signal = task_signal
        .derive(Kind::GateVerdict, Body::from_json(&verdict).unwrap())
        .tag("gate", &verdict.gate)
        .tag("passed", &verdict.passed.to_string())
        .build();
    substrate.put(verdict_signal.clone()).await.unwrap();

    // 4. Query for gate verdicts — the verdict is now substrate-queryable.
    let verdicts = substrate
        .query(
            &roko_core::Query::of_kind(Kind::GateVerdict),
            &Context::now(),
        )
        .await
        .unwrap();

    assert_eq!(verdicts.len(), 1);
    assert_eq!(verdicts[0].lineage, vec![task_signal.id]);
    assert_eq!(verdicts[0].tag("passed"), Some("true"));
}

/// A wrapper that upgrades a Gate into a Substrate-writing policy — showing
/// how gates and substrates naturally compose.
struct PersistingGate<G: Gate> {
    inner: G,
    substrate: std::sync::Arc<dyn Substrate>,
}

#[async_trait]
impl<G: Gate> Gate for PersistingGate<G> {
    async fn verify(&self, signal: &Signal, ctx: &Context) -> roko_core::Verdict {
        let verdict = self.inner.verify(signal, ctx).await;
        let verdict_signal = signal
            .derive(
                Kind::GateVerdict,
                Body::from_json(&verdict).unwrap_or(Body::Empty),
            )
            .tag("gate", &verdict.gate)
            .tag("passed", &verdict.passed.to_string())
            .build();
        let _ = self.substrate.put(verdict_signal).await;
        verdict
    }

    fn name(&self) -> &str {
        self.inner.name()
    }
}

#[tokio::test]
async fn gate_composes_with_substrate_as_adapter() {
    let tmp = TempDir::new().unwrap();
    scaffold_cargo_project(tmp.path(), "pub fn y() -> bool { true }\n").await;

    let substrate: std::sync::Arc<dyn Substrate> = std::sync::Arc::new(MemorySubstrate::new());
    let gate = PersistingGate {
        inner: CompileGate::new(BuildSystem::Cargo).with_timeout_ms(120_000),
        substrate: substrate.clone(),
    };

    let signal = payload_signal(tmp.path());
    let verdict = gate.verify(&signal, &Context::now()).await;
    assert!(verdict.passed);

    // The gate persisted its own verdict as a signal.
    let stored = substrate
        .query(
            &roko_core::Query::of_kind(Kind::GateVerdict),
            &Context::now(),
        )
        .await
        .unwrap();
    assert_eq!(stored.len(), 1);
    assert_eq!(stored[0].tag("gate"), Some("compile:cargo"));
}

